using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 500;
    public int baseDamage = 10;
    public float damageMultiplier = 1f;

    public bool IsAlive => currentHealth > 0;

    private void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public int CalculateDamage()
    {
        return Mathf.Max(1, Mathf.RoundToInt(baseDamage * damageMultiplier));
    }

    public void TakeDamage(int incomingDamage)
    {
        int finalDamage = Mathf.Max(0, incomingDamage);
        currentHealth = Mathf.Max(0, currentHealth - finalDamage);
    }

    public void Heal(int amount)
    {
        currentHealth = Mathf.Clamp(currentHealth + Mathf.Max(0, amount), 0, maxHealth);
    }

    public void AddCurrency(int amount)
    {
        currency += Mathf.Max(0, amount);
    }

    public bool SpendCurrency(int amount)
    {
        int price = Mathf.Max(0, amount);
        if (currency < price)
            return false;

        currency -= price;
        return true;
    }
}

public class Enemy : MonoBehaviour
{
    public int maxHealth = 50;
    public int currentHealth = 50;
    public int defense = 2;

    public bool IsAlive => currentHealth > 0;

    private void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public void TakeDamage(int rawDamage)
    {
        int finalDamage = Mathf.Max(0, rawDamage - defense);
        currentHealth = Mathf.Max(0, currentHealth - finalDamage);
    }
}

public class CombatSystem : MonoBehaviour
{
    public PlayerStats player;

    public int CalculateFinalDamageAgainstEnemy(Enemy enemy)
    {
        if (player == null || enemy == null)
            return 0;

        int playerDamage = player.CalculateDamage();
        return Mathf.Max(0, playerDamage - enemy.defense);
    }

    public void AttackEnemy(Enemy enemy)
    {
        if (player == null || enemy == null || !player.IsAlive || !enemy.IsAlive)
            return;

        int damage = player.CalculateDamage();
        enemy.TakeDamage(damage);
    }

    public void EnemyAttackPlayer(int enemyDamage)
    {
        if (player == null || !player.IsAlive)
            return;

        player.TakeDamage(enemyDamage);
    }
}

[System.Serializable]
public class ShopItem
{
    public string itemName;
    public int basePrice = 100;
    public int level = 0;
    public int priceIncreasePerLevel = 25;
    public int damageIncrease = 5;
    public int healthIncrease = 10;

    public int CalculatePrice()
    {
        return Mathf.Max(0, basePrice + (level * priceIncreasePerLevel));
    }
}

public class ShopSystem : MonoBehaviour
{
    public PlayerStats player;
    public ShopItem damageUpgrade;
    public ShopItem healthUpgrade;

    public int GetItemPrice(ShopItem item)
    {
        if (item == null)
            return 0;

        return item.CalculatePrice();
    }

    public bool PurchaseDamageUpgrade()
    {
        if (player == null || damageUpgrade == null)
            return false;

        int price = damageUpgrade.CalculatePrice();
        if (!player.SpendCurrency(price))
            return false;

        player.baseDamage += damageUpgrade.damageIncrease;
        damageUpgrade.level++;
        return true;
    }

    public bool PurchaseHealthUpgrade()
    {
        if (player == null || healthUpgrade == null)
            return false;

        int price = healthUpgrade.CalculatePrice();
        if (!player.SpendCurrency(price))
            return false;

        player.maxHealth += healthUpgrade.healthIncrease;
        player.currentHealth += healthUpgrade.healthIncrease;
        healthUpgrade.level++;
        return true;
    }

    public bool PurchaseCurrencyPack(int amount, int localPriceValue)
    {
        if (player == null)
            return false;

        int validatedAmount = Mathf.Max(0, amount);
        int validatedLocalPrice = Mathf.Max(0, localPriceValue);

        if (validatedLocalPrice >= 0)
        {
            player.AddCurrency(validatedAmount);
            return true;
        }

        return false;
    }
}